/* Test driver */
import java.time.LocalDateTime;
public class Main {
    public static void main(String[] args) {
        BookingSystem sys = new BookingSystem();
        Room r = new Room("r1", "RoomA", 4, 1, Room.Amenity.WHITEBOARD);
        sys.addRoom(r);
        User a = new User("u1", "Alice", "Eng", 1);
        TimeSlot first = new TimeSlot(LocalDateTime.of(2026,5,15,9,0), LocalDateTime.of(2026,5,15,9,30));
        BookingComponent series = sys.createRecurringBooking(r, first, a, MeetingType.STANDUP, "Daily", RecurringBooking.Frequency.DAILY, 3);
        if (series.getTimeSlots().size() == 3 && series.getId().startsWith("SER-")) System.out.println("OK_RECUR=" + series.getTimeSlots().size());
        sys.cancelBooking(series.getId());
        boolean allCancelled = true;
        for (Booking bk : ((RecurringBooking)series).getBookings()) if (!bk.isCancelled()) allCancelled = false;
        if (allCancelled) System.out.println("OK_COMPOSITE_CANCEL");
    }
}

/* Test driver */
import java.time.LocalDateTime;
import java.util.HashSet;
import java.util.Set;
public class Main {
    public static void main(String[] args) {
        BookingSystem sys = new BookingSystem();
        Room small = new Room("r1", "Small", 4, 1, Room.Amenity.WHITEBOARD);
        Room big = new Room("r2", "Big", 20, 2, Room.Amenity.PROJECTOR, Room.Amenity.WHITEBOARD);
        sys.addRoom(small); sys.addRoom(big);
        TimeSlot slot = new TimeSlot(LocalDateTime.of(2026,5,15,9,0), LocalDateTime.of(2026,5,15,10,0));
        Set<Room.Amenity> need = new HashSet<>();
        need.add(Room.Amenity.PROJECTOR);
        Room found = sys.findAvailableRoom(6, need, slot);
        if (found != null && found.getName().equals("Big")) System.out.println("OK_FIND=" + found.getName());
        Room foundLarge = sys.findAvailableRoom(50, new HashSet<>(), slot);
        if (foundLarge == null) System.out.println("OK_NO_FIT");
    }
}
